public class Main {
    public static void main(String[] args) {
        // Widening (automatic)
        int myInt = 9;
        double myDouble = myInt;
        System.out.println("Widened double: " + myDouble);

        // Narrowing (manual)
        double d = 9.78;
        int i = (int) d;
        System.out.println("Narrowed int: " + i);

        // String to int
        String s = "456";
        int parsed = Integer.parseInt(s);
        System.out.println("Parsed int: " + parsed);
    }
}
